// src/pages/DashboardPage.js
import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useRole } from '../context/RoleContext';
import { useToast } from '../context/ToastContext';
import { useSensor } from '../hooks/useSensor';
import FileAttachment from '../components/health-records/FileAttachment';
import healthRecordService from '../services/healthRecordService';
import appointmentService from '../services/appointmentService';
import AppointmentCalendar from '../components/appointments/AppointmentCalendar';
import PrescriptionList from '../components/prescriptions/PrescriptionList';
import SkeletonLoader from '../components/common/SkeletonLoader';
import AddPatientForm from '../components/patients/AddPatientForm';
import PatientList from '../components/patients/PatientList';
import './DashboardPage.css';

const DashboardPage = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const { loading: roleLoading } = useRole();
    const { showSuccess, showError } = useToast();
    const { status: sensorStatus, connect } = useSensor();
    
    const [activeTab, setActiveTab] = useState('records');
    const [records, setRecords] = useState([]);
    const [recordsLoading, setRecordsLoading] = useState(true);
    const [recordsError, setRecordsError] = useState('');
    const [showAddForm, setShowAddForm] = useState(false);
    const [newRecord, setNewRecord] = useState({
        title: '',
        description: '',
        type: 'general'
    });
    const [selectedFile, setSelectedFile] = useState(null);
    const [uploading, setUploading] = useState(false);
    const [attachments, setAttachments] = useState({});
    const [appointmentsLoading, setAppointmentsLoading] = useState(false);
    const [appointmentsError, setAppointmentsError] = useState('');
    const [showAddPatientForm, setShowAddPatientForm] = useState(false);
    const [refreshPatients, setRefreshPatients] = useState(false);
    const [showSensorPrompt, setShowSensorPrompt] = useState(false);
    const [isConnecting, setIsConnecting] = useState(false);
    const [stats, setStats] = useState({
        totalRecords: 0,
        totalAppointments: 0,
        totalPrescriptions: 0
    });

    // Check if user can manage patients (master_admin, receptionist, ict_admin)
    const canManagePatients = user?.role === 'master_admin' || user?.role === 'receptionist' || user?.role === 'ict_admin';
    
    // Check if user is master admin
    const isMasterAdmin = user?.role === 'master_admin';

    const fetchAttachments = useCallback(async (recordId) => {
        try {
            const data = await healthRecordService.getAttachments(recordId);
            setAttachments(prev => ({ ...prev, [recordId]: data }));
        } catch (error) {
            console.error('Failed to fetch attachments:', error);
        }
    }, []);

    // DO NOT redirect master admin - they should have access to dashboard
    useEffect(() => {
        if (!roleLoading && user) {
            console.log('Current user role:', user.role);
            console.log('Is master admin:', isMasterAdmin);
            console.log('Can manage patients:', canManagePatients);
        }
    }, [roleLoading, user, isMasterAdmin, canManagePatients]);

    useEffect(() => {
        const wasConnected = localStorage.getItem('sensorConnected') === 'true';
        if (wasConnected && !sensorStatus.connected) {
            setShowSensorPrompt(true);
        }
    }, [sensorStatus.connected]);

    const fetchRecords = useCallback(async () => {
        try {
            setRecordsLoading(true);
            const data = await healthRecordService.getRecords();
            setRecords(data);
            setStats(prev => ({ ...prev, totalRecords: data.length }));
            
            if (data && data.length > 0) {
                data.forEach(record => {
                    fetchAttachments(record.id);
                });
            }
        } catch (err) {
            setRecordsError('Failed to load health records');
            showError('Failed to load health records');
        } finally {
            setRecordsLoading(false);
        }
    }, [showError, fetchAttachments]);

    const fetchAppointments = useCallback(async () => {
        try {
            setAppointmentsLoading(true);
            const data = await appointmentService.getAppointments();
            setStats(prev => ({ ...prev, totalAppointments: data?.length || 0 }));
        } catch (err) {
            setAppointmentsError('Failed to load appointments');
            showError('Failed to load appointments');
        } finally {
            setAppointmentsLoading(false);
        }
    }, [showError]);

    useEffect(() => {
        if (activeTab === 'records') {
            fetchRecords();
        } else if (activeTab === 'appointments') {
            fetchAppointments();
        }
    }, [activeTab, fetchRecords, fetchAppointments]);

    const handleInputChange = (e) => {
        setNewRecord({
            ...newRecord,
            [e.target.name]: e.target.value
        });
    };

    const handleFileSelect = (e) => {
        const file = e.target.files[0];
        if (file) {
            if (file.size > 10 * 1024 * 1024) {
                showError('File size must be less than 10MB');
                return;
            }
            
            const allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'application/pdf', 'application/msword', 'text/plain'];
            if (!allowedTypes.includes(file.type)) {
                showError('Invalid file type. Allowed: JPG, PNG, GIF, PDF, DOC, TXT');
                return;
            }
            
            setSelectedFile(file);
        }
    };

    const clearSelectedFile = () => {
        setSelectedFile(null);
        const fileInput = document.getElementById('record-file');
        if (fileInput) fileInput.value = '';
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!newRecord.title) {
            showError('Please enter a title for your health record');
            return;
        }
        
        setUploading(true);
        
        try {
            const recordData = {
                title: newRecord.title,
                text: newRecord.description || '',
                type: newRecord.type,
                date: new Date().toISOString()
            };
            
            if (selectedFile) {
                await healthRecordService.createRecordWithFile(recordData, selectedFile);
                showSuccess('Health record with attachment added successfully');
            } else {
                await healthRecordService.createRecord(recordData);
                showSuccess('Health record created successfully');
            }
            
            setShowAddForm(false);
            setNewRecord({ title: '', description: '', type: 'general' });
            clearSelectedFile();
            fetchRecords();
        } catch (err) {
            showError(err.message || 'Failed to create record');
        } finally {
            setUploading(false);
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this record?')) {
            try {
                await healthRecordService.deleteRecord(id);
                showSuccess('Record deleted successfully');
                fetchRecords();
            } catch (err) {
                showError('Failed to delete record');
            }
        }
    };

    const handleConnectSensor = async () => {
        setIsConnecting(true);
        try {
            const result = await connect();
            if (result.success) {
                localStorage.setItem('sensorConnected', 'true');
                showSuccess('Fingerprint sensor connected!');
                setShowSensorPrompt(false);
            } else {
                showError(`Connection failed: ${result.error}`);
            }
        } catch (err) {
            showError(`Connection error: ${err.message}`);
        } finally {
            setIsConnecting(false);
        }
    };

    const handleDismissSensor = () => {
        setShowSensorPrompt(false);
        localStorage.removeItem('sensorConnected');
    };

    const handlePatientAdded = () => {
        setShowAddPatientForm(false);
        setRefreshPatients(!refreshPatients);
        showSuccess('Patient registered successfully!');
    };

    const getRecordTypeIcon = (type) => {
        const icons = {
            general: '📋',
            prescription: '💊',
            lab_result: '🔬',
            imaging: '🖼️',
            vaccination: '💉'
        };
        return icons[type] || '📄';
    };

    const getRecordTypeColor = (type) => {
        const colors = {
            general: '#667eea',
            prescription: '#48bb78',
            lab_result: '#4299e1',
            imaging: '#ed8936',
            vaccination: '#9f7aea'
        };
        return colors[type] || '#718096';
    };

    const goToProfile = () => {
        navigate('/profile');
    };

    const getFileIcon = () => {
        if (!selectedFile) return '📎';
        if (selectedFile.type.startsWith('image/')) return '🖼️';
        if (selectedFile.type === 'application/pdf') return '📄';
        if (selectedFile.type.includes('word')) return '📝';
        return '📎';
    };

    const formatFileSize = (bytes) => {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
    };

    const renderHealthRecords = () => {
        if (recordsLoading) {
            return <SkeletonLoader type="card" count={3} />;
        }

        if (recordsError) {
            return <div className="error-message">{recordsError}</div>;
        }

        if (records.length === 0) {
            return (
                <div className="empty-state">
                    <div className="empty-state-icon">📋</div>
                    <h3>No Health Records Yet</h3>
                    <p>Start tracking your health by adding your first record.</p>
                    <button className="btn btn-primary" onClick={() => setShowAddForm(true)}>
                        + Create Your First Record
                    </button>
                </div>
            );
        }

        return (
            <div className="records-grid">
                {records.map((record) => {
                    let recordData = record.record_data;
                    let title = '';
                    let description = '';
                    let recordType = record.record_type || 'general';
                    
                    if (typeof recordData === 'string') {
                        try {
                            const parsed = JSON.parse(recordData);
                            title = parsed.title || '';
                            description = parsed.text || parsed.description || '';
                            recordType = parsed.type || recordType;
                        } catch (e) {
                            description = recordData;
                            title = recordData.substring(0, 50) || 'Health Record';
                        }
                    } else if (recordData && typeof recordData === 'object') {
                        title = recordData.title || '';
                        description = recordData.text || recordData.description || '';
                        recordType = recordData.type || recordType;
                    }
                    
                    if (!title && description) {
                        title = description.substring(0, 50);
                        if (description.length > 50) title += '...';
                    }
                    
                    return (
                        <div key={record.id} className="record-card">
                            <div className="record-card-header">
                                <div className="record-type-badge" style={{ backgroundColor: getRecordTypeColor(recordType) }}>
                                    {getRecordTypeIcon(recordType)}
                                    <span>{recordType.replace('_', ' ').toUpperCase()}</span>
                                </div>
                                <button 
                                    className="delete-btn"
                                    onClick={() => handleDelete(record.id)}
                                    title="Delete record"
                                >
                                    ×
                                </button>
                            </div>
                            <div className="record-card-body">
                                <h3>{title || 'Untitled Record'}</h3>
                                <div className="record-meta">
                                    <span className="record-date">
                                        📅 {new Date(record.created_at).toLocaleDateString('en-US', { 
                                            year: 'numeric', 
                                            month: 'long', 
                                            day: 'numeric' 
                                        })}
                                    </span>
                                </div>
                                {description && (
                                    <p className="record-description">{description}</p>
                                )}
                                <FileAttachment 
                                    recordId={record.id}
                                    attachments={attachments[record.id] || []}
                                    onAttachmentChange={() => fetchAttachments(record.id)}
                                />
                            </div>
                        </div>
                    );
                })}
            </div>
        );
    };

    const renderAppointments = () => {
        if (appointmentsLoading) {
            return <SkeletonLoader type="card" count={2} />;
        }

        if (appointmentsError) {
            return <div className="error-message">{appointmentsError}</div>;
        }

        return <AppointmentCalendar />;
    };

    const renderPatientManagement = () => {
        return (
            <div className="patient-management-tab">
                <div className="section-header">
                    <h2>Patient Management</h2>
                    <button 
                        className="btn-get-started"
                        onClick={() => setShowAddPatientForm(!showAddPatientForm)}
                    >
                        {showAddPatientForm ? '✕ Cancel' : '+ Register New Patient'}
                    </button>
                </div>

                {showAddPatientForm && (
                    <div className="add-patient-container">
                        <AddPatientForm 
                            onPatientAdded={handlePatientAdded}
                            onCancel={() => setShowAddPatientForm(false)}
                        />
                    </div>
                )}

                <div className="patients-section">
                    <div className="section-header">
                        <h3>All Patients</h3>
                    </div>
                    <PatientList refresh={refreshPatients} />
                </div>
            </div>
        );
    };

    if (roleLoading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner"></div>
                <p>Loading your dashboard...</p>
            </div>
        );
    }

    return (
        <div className="dashboard-page">
            {/* Sensor Connection Prompt */}
            {showSensorPrompt && (
                <div className="sensor-prompt-overlay">
                    <div className="sensor-prompt">
                        <div className="sensor-prompt-icon">🔌</div>
                        <h3>Reconnect Fingerprint Sensor?</h3>
                        <p>Your fingerprint sensor was previously connected. Connect now for quick authentication?</p>
                        <div className="sensor-prompt-actions">
                            <button 
                                className="btn-primary"
                                onClick={handleConnectSensor}
                                disabled={isConnecting}
                            >
                                {isConnecting ? 'Connecting...' : 'Yes, Connect'}
                            </button>
                            <button 
                                className="btn-secondary"
                                onClick={handleDismissSensor}
                            >
                                Not Now
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Welcome Header */}
            <div className="dashboard-header">
                <div className="welcome-section">
                    <div className="welcome-badge">
                        <span className="welcome-icon">👋</span>
                        <span className="welcome-text">Welcome back,</span>
                    </div>
                    <h1 className="welcome-name">{user?.username || 'User'}!</h1>
                    <p className="welcome-message">Here's what's happening with your health today.</p>
                </div>
                <button className="profile-btn" onClick={goToProfile}>
                    <span className="profile-icon">👤</span>
                    <span>Profile</span>
                </button>
            </div>

            {/* Stats Cards */}
            <div className="stats-grid">
                <div className="stat-card">
                    <div className="stat-icon">📋</div>
                    <div className="stat-info">
                        <h3>{stats.totalRecords}</h3>
                        <p>Health Records</p>
                    </div>
                </div>
                <div className="stat-card">
                    <div className="stat-icon">📅</div>
                    <div className="stat-info">
                        <h3>{stats.totalAppointments}</h3>
                        <p>Appointments</p>
                    </div>
                </div>
                <div className="stat-card">
                    <div className="stat-icon">💊</div>
                    <div className="stat-info">
                        <h3>{stats.totalPrescriptions}</h3>
                        <p>Prescriptions</p>
                    </div>
                </div>
            </div>

            {/* Tab Navigation */}
            <div className="dashboard-tabs">
                <button 
                    className={`tab-btn ${activeTab === 'records' ? 'active' : ''}`}
                    onClick={() => setActiveTab('records')}
                >
                    <span className="tab-icon">📋</span>
                    <span>Health Records</span>
                </button>
                <button 
                    className={`tab-btn ${activeTab === 'appointments' ? 'active' : ''}`}
                    onClick={() => setActiveTab('appointments')}
                >
                    <span className="tab-icon">📅</span>
                    <span>Appointments</span>
                </button>
                <button 
                    className={`tab-btn ${activeTab === 'prescriptions' ? 'active' : ''}`}
                    onClick={() => setActiveTab('prescriptions')}
                >
                    <span className="tab-icon">💊</span>
                    <span>Prescriptions</span>
                </button>
                {/* Show Patient Management tab for master_admin, receptionist, and ict_admin */}
                {canManagePatients && (
                    <button 
                        className={`tab-btn ${activeTab === 'patients' ? 'active' : ''}`}
                        onClick={() => setActiveTab('patients')}
                    >
                        <span className="tab-icon">👥</span>
                        <span>Manage Patients</span>
                    </button>
                )}
            </div>

            {/* Content Area */}
            <div className="dashboard-content">
                {activeTab === 'records' && (
                    <div className="content-panel">
                        <div className="panel-header">
                            <h2>Your Health Records</h2>
                            <button 
                                className="btn-get-started"
                                onClick={() => setShowAddForm(!showAddForm)}
                            >
                                {showAddForm ? '✕ Cancel' : '+ Add New Record'}
                            </button>
                        </div>

                        {showAddForm && (
                            <div className="add-record-form">
                                <h3>Create New Health Record</h3>
                                <form onSubmit={handleSubmit}>
                                    <div className="form-row">
                                        <div className="form-group">
                                            <label>Record Type</label>
                                            <select 
                                                name="type" 
                                                value={newRecord.type}
                                                onChange={handleInputChange}
                                                required
                                            >
                                                <option value="general">📋 General</option>
                                                <option value="prescription">💊 Prescription</option>
                                                <option value="lab_result">🔬 Lab Result</option>
                                                <option value="imaging">🖼️ Imaging</option>
                                                <option value="vaccination">💉 Vaccination</option>
                                            </select>
                                        </div>

                                        <div className="form-group">
                                            <label>Title *</label>
                                            <input
                                                type="text"
                                                name="title"
                                                value={newRecord.title}
                                                onChange={handleInputChange}
                                                placeholder="Enter record title"
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div className="form-group">
                                        <label>Description</label>
                                        <textarea
                                            name="description"
                                            value={newRecord.description}
                                            onChange={handleInputChange}
                                            placeholder="Enter record details..."
                                            rows="4"
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label>Attachment (Optional)</label>
                                        <div className="file-upload-area">
                                            <input
                                                type="file"
                                                id="record-file"
                                                onChange={handleFileSelect}
                                                accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt"
                                                className="file-input"
                                            />
                                            <label htmlFor="record-file" className="file-label">
                                                <span>📎</span> Choose File
                                            </label>
                                            {selectedFile && (
                                                <div className="selected-file-info">
                                                    <span className="file-icon">{getFileIcon()}</span>
                                                    <span className="file-name">{selectedFile.name}</span>
                                                    <span className="file-size">({formatFileSize(selectedFile.size)})</span>
                                                    <button 
                                                        type="button"
                                                        onClick={clearSelectedFile}
                                                        className="remove-file"
                                                    >
                                                        ×
                                                    </button>
                                                </div>
                                            )}
                                        </div>
                                        <small className="file-hint">
                                            Supported: JPG, PNG, GIF, PDF, DOC, TXT (Max 10MB)
                                        </small>
                                    </div>

                                    <div className="form-actions">
                                        <button 
                                            type="button"
                                            className="btn-cancel"
                                            onClick={() => setShowAddForm(false)}
                                        >
                                            Cancel
                                        </button>
                                        <button 
                                            type="submit" 
                                            className="btn-get-started"
                                            disabled={uploading}
                                        >
                                            {uploading ? 'Saving...' : 'Save Record'}
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}

                        {renderHealthRecords()}
                    </div>
                )}

                {activeTab === 'appointments' && (
                    <div className="content-panel">
                        <div className="panel-header">
                            <h2>Appointment Calendar</h2>
                        </div>
                        {renderAppointments()}
                    </div>
                )}

                {activeTab === 'prescriptions' && (
                    <div className="content-panel">
                        <div className="panel-header">
                            <h2>Your Prescriptions</h2>
                        </div>
                        <PrescriptionList />
                    </div>
                )}

                {activeTab === 'patients' && canManagePatients && renderPatientManagement()}
            </div>
        </div>
    );
};

export default DashboardPage;
